import{_ as e,o as t,c as l,aw as o}from"./chunks/framework.DLufY-ao.js";const g=JSON.parse('{"title":"Элементы разметки Layout","description":"","frontmatter":{},"headers":[],"relativePath":"wiki/dev-commit/layout/html/category/layout.md","filePath":"wiki/dev-commit/layout/html/category/layout.md"}'),i={name:"wiki/dev-commit/layout/html/category/layout.md"};function d(r,a,c,n,h,u){return t(),l("div",null,[...a[0]||(a[0]=[o('<h1 id="элементы-разметки-layout" tabindex="-1">Элементы разметки Layout <a class="header-anchor" href="#элементы-разметки-layout" aria-label="Permalink to &quot;Элементы разметки Layout&quot;">​</a></h1><h2 id="элементы" tabindex="-1">Элементы <a class="header-anchor" href="#элементы" aria-label="Permalink to &quot;Элементы&quot;">​</a></h2><h3 id="header" tabindex="-1"><code>&lt;header /&gt;</code> <a class="header-anchor" href="#header" aria-label="Permalink to &quot;`&lt;header /&gt;`&quot;">​</a></h3><ul><li>Задаёт «шапку» сайта или раздела, в которой обычно располагается заголовок</li></ul><h3 id="nav" tabindex="-1"><code>&lt;nav /&gt;</code> <a class="header-anchor" href="#nav" aria-label="Permalink to &quot;`&lt;nav /&gt;`&quot;">​</a></h3><ul><li>Задаёт навигацию по сайту</li><li>Если на странице несколько блоков ссылок, то в <code>&lt;nav&gt;</code> обычно помещают приоритетные ссылки</li><li>Также допустимо использовать несколько <code>&lt;nav&gt;</code> в документе. Запрещается вкладывать <code>&lt;nav&gt;</code> внутрь <code>&lt;address&gt;</code></li></ul><h3 id="main" tabindex="-1"><code>&lt;main /&gt;</code> <a class="header-anchor" href="#main" aria-label="Permalink to &quot;`&lt;main /&gt;`&quot;">​</a></h3><ul><li>Предназначен для основного содержимого документа</li><li>На странице может быть только один <code>&lt;main&gt;</code> и он не должен располагаться внутри элементов <code>&lt;article&gt;</code>, <code>&lt;aside&gt;</code>, <code>&lt;footer&gt;</code>, <code>&lt;header&gt;</code> или <code>&lt;nav&gt;</code></li></ul><h3 id="section" tabindex="-1"><code>&lt;section /&gt;</code> <a class="header-anchor" href="#section" aria-label="Permalink to &quot;`&lt;section /&gt;`&quot;">​</a></h3><ul><li>Задаёт раздел документа, может применяться для блока новостей, контактной информации, глав текста, вкладок в диалоговом окне и др.</li><li>Раздел обычно содержит заголовок</li></ul><h3 id="footer" tabindex="-1"><code>&lt;footer /&gt;</code> <a class="header-anchor" href="#footer" aria-label="Permalink to &quot;`&lt;footer /&gt;`&quot;">​</a></h3><ul><li>Задаёт «подвал» сайта или раздела, в нём может располагаться имя автора, дата документа, контактная и правовая информация</li></ul><h3 id="article" tabindex="-1"><code>&lt;article /&gt;</code> <a class="header-anchor" href="#article" aria-label="Permalink to &quot;`&lt;article /&gt;`&quot;">​</a></h3><ul><li>Задаёт содержание сайта вроде новости, статьи, записи блога, форума и др.</li></ul><h3 id="aside" tabindex="-1"><code>&lt;aside /&gt;</code> <a class="header-anchor" href="#aside" aria-label="Permalink to &quot;`&lt;aside /&gt;`&quot;">​</a></h3><ul><li>Определяет блок сбоку от контента для размещения рубрик, ссылок на архив, меток и другой информации</li><li>Такой блок, как правило, называется «сайдбар» или «боковая панель».</li></ul><h3 id="figure" tabindex="-1"><code>&lt;figure /&gt;</code> <a class="header-anchor" href="#figure" aria-label="Permalink to &quot;`&lt;figure /&gt;`&quot;">​</a></h3><ul><li>Используется для группирования любых элементов, например, изображений и подписей к ним. <code>&lt;figure&gt;</code> не должен быть связан непосредственно с основным содержимым документа и при его перемещении в другое место смысл текста не должен меняться</li><li>Обычно применяется для иллюстраций, фрагментов кода, схем, графиков, диаграмм и др.</li></ul>',18)])])}const m=e(i,[["render",d]]);export{g as __pageData,m as default};
